function (train_data, test_data, target_variable, iterations = c(50,      100, 500), depth = c(4, 6, 8), learning_rate = c(0.01, 0.05,      0.1), seed = 123)  {     if (!requireNamespace("catboost", quietly = TRUE)) {         install.packages("catboost")     }     library(catboost)     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     X_test <- test_data[, colnames(X_train), drop = FALSE]     y_test <- test_data[[target_variable]]     X_train <- as.matrix(X_train)     X_test <- as.matrix(X_test)     y_test <- as.numeric(y_test)     y_train <- as.numeric(y_train)     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     for (iterations in iterations) {         for (depth in depth) {             for (learning_rate in learning_rate) {                 set.seed(seed)                 train_pool <- catboost.load_pool(data = X_train,                    label = y_train)                 test_pool <- catboost.load_pool(data = X_test)                 params <- list(iterations = iterations, depth = depth,                    learning_rate = learning_rate, loss_function = "RMSE")                 catboost_model <- catboost.train(train_pool,                    params = params)                 predictions <- catboost.predict(catboost_model,                    test_pool)                 predictions <- as.numeric(predictions)                 rmse <- sqrt(mean((y_test - predictions)^2))                 correlation <- cor(predictions, y_test, use = "complete.obs")                 if (rmse < best_rmse || (rmse == best_rmse &&                    correlation > best_correlation)) {                   best_rmse <- rmse                   best_correlation <- correlation                   best_params <- list(interations = iterations,                      depth = depth, learning_rate = learning_rate)                   best_predictions <- predictions                   best_model <- catboost_model                 }             }         }     }     return(list(best_predictions = best_predictions, best_rmse = best_rmse,          best_correlation = best_correlation, best_params = best_params,          best_model = best_model)) }